BlockListener = {}

function BlockListener:init()
    Listener.registerCallBack(BlockStartBreakEvent, function(_, blockId, blockPos)
        return BlockListener.checkBreakBlock(_, blockId, blockPos, 15)
    end)
    Listener.registerCallBack(BlockAbortBreakEvent, function(_, blockId, blockPos)
        return BlockListener.checkBreakBlock(_, blockId, blockPos, 2)
    end)
    Listener.registerCallBack(BlockBreakEvent, function(_, blockId, blockPos)
        return BlockListener.checkBreakBlock(_, blockId, blockPos, 2)
    end)
    Listener.registerCallBack(PlayerPlaceBlockEvent, function(_, blockId, blockMeta, blockPos)
        return BlockListener.checkPlaceBlock(_, blockId, blockMeta, blockPos)
    end)
    Listener.registerCallBack(BlockCanHarvestEvent, function(blockId)
        return BlockListener.onBlockCanHarvest(blockId)
    end)
end

function BlockListener.checkBreakBlock(_, blockId, blockPos, tipTime)
    if ItemMapping:getOldItemId(ItemMapping:getOldItemId(blockId)) ~= BlockID.OBSIDIAN then
        --黑曜石
        return true
    end
    local heldItemId = PlayerManager:getClientPlayer().Player:getHeldItemId()
    if ItemMapping:getOldItemId(heldItemId) == ItemID.PICKAXE_DIAMOND then
        ---稿子钻石类型的可以破坏黑曜石
        return true
    end
    MsgSender.sendBottomTips(tipTime, 1008021)
    return false
end

function BlockListener.checkPlaceBlock(_, blockId, blockMeta, blockPos)
    local isInArea = TeamConfig:isInTeamArea(blockPos)
    if not isInArea then
        return true
    end
    local tipStr = Lang:getTipString(1008002)
    local heldItemId = PlayerManager:getClientPlayer().Player:getHeldItemId()
    if heldItemId == 2417
        or heldItemId == 2418
    then
        GUIBedWarGameTips:showGameTip(tipStr)
        return false
    end
    return true
end

function BlockListener.onBlockCanHarvest(blockId)
    if ItemMapping:getOldItemId(ItemMapping:getOldItemId(blockId)) ~= BlockID.OBSIDIAN then
        --不是黑曜石，使用引擎默认的
        return true
    end
    local heldItemId = PlayerManager:getClientPlayer().Player:getHeldItemId()
    if ItemMapping:getOldItemId(heldItemId) == ItemID.PICK_AXE_GOLD  then
        ---金稿子 破坏黑曜石 速度是快的，其他稿子都是慢的
        return true
    end
    return false
end